PlayerAIListener = {}

function PlayerAIListener:init()
    BaseListener.registerCallBack(PlayerDynamicAttrEvent, self.onDynamicAttrInit)
    PlayerAIArriveEvent.registerCallBack(self.onPlayerAIArrive)
    PlayerAIMoveFailEvent.registerCallBack(self.onPlayerAIMoveFail)
end

local index = 0
function PlayerAIListener.onDynamicAttrInit(attr)
    if attr.isRobot == false then
        return
    end
    local platformId = attr.userId
    local robotId = attr.robotId
    local teamId = attr.team
    local name = tostring(attr.name)
    index = index + 1
    LuaTimer:schedule(function()
        AITeamManager:newAi(robotId, teamId, platformId, name)
    end, 50 * index)
end

function PlayerAIListener.onPlayerAIArrive(rakssid)
    local playerAI = AIManager:getAIByRakssid(rakssid)
    if not playerAI then
        return
    end
    local path = playerAI.curPath
    if playerAI.curPath == nil or #playerAI.curPath == 0 then
        playerAI:stopMove()
        return true
    end
    local pos = playerAI.entity:getPosition()
    if path[#path].x == math.floor(pos.x) and path[#path].z == math.floor(pos.z) then
        playerAI.needMoveBlock = playerAI.needMoveBlock - 1
        table.remove(path, #path)
        path = playerAI:updatePath()
    end
    if #path == 0 then
        playerAI:stopMove()
        return true
    end
    playerAI:moveTo(path[#path])
    return false
end

function PlayerAIListener.onPlayerAIMoveFail(rakssid)
    local playerAI = AIManager:getAIByRakssid(rakssid)
    if playerAI then
        playerAI:stopMove()
        return true
    end
    return false
end

